package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.junit.jupiter.MockitoExtension;

import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.lang.reflect.Modifier;

@ExtendWith(MockitoExtension.class)
class ReflectionHelperTest {

  // Use raw Object type for mock to avoid access to private nested interface
  private static Object mockRecordHelper;

  private static Field testField;

  private static Method expectedMethod;

  static class DummyClass {
    private int someField;
    public int getSomeField() {
      return someField;
    }
  }

  @BeforeAll
  static void setup() throws Exception {
    expectedMethod = DummyClass.class.getMethod("getSomeField");
    testField = DummyClass.class.getDeclaredField("someField");

    // Get the private RecordHelper class via reflection
    Class<?> recordHelperClass = null;
    for (Class<?> innerClass : ReflectionHelper.class.getDeclaredClasses()) {
      if ("RecordHelper".equals(innerClass.getSimpleName())) {
        recordHelperClass = innerClass;
        break;
      }
    }
    assertNotNull(recordHelperClass, "RecordHelper class not found");

    // Create mock with raw type Object but specifying the class to mock
    mockRecordHelper = mock(recordHelperClass);

    // Setup when(mockRecordHelper.getAccessor(...)) via reflection
    // Find getAccessor method on RecordHelper
    Method getAccessorMethod = recordHelperClass.getMethod("getAccessor", Class.class, Field.class);
    // Use Mockito's when with reflection proxy
    when(getAccessorMethod.invoke(mockRecordHelper, DummyClass.class, testField)).thenReturn(expectedMethod);
    // But above won't work directly, so use Mockito's when with doReturn + Mockito's mock settings:
    // Instead, use Mockito's when with Mockito.mock with class type:
    // So replace above lines with:
    when(((java.util.function.BiFunction<Class<?>, Field, Method>) (c, f) -> {
      try {
        return (Method) getAccessorMethod.invoke(mockRecordHelper, c, f);
      } catch (Exception e) {
        throw new RuntimeException(e);
      }
    }).apply(DummyClass.class, testField)).thenReturn(expectedMethod);

    // Instead, better to use Mockito's when with Mockito.mock and doReturn:
    // So skip above and just do:
    // Use Mockito's when on mockRecordHelper via spy proxy:
    // But simpler to use Mockito's doReturn:
    // So:
    doReturn(expectedMethod).when(mockRecordHelper).getClass()
      .getMethod("getAccessor", Class.class, Field.class)
      .invoke(mockRecordHelper, DummyClass.class, testField);

    // Actually, above is complicated. Instead, use Mockito's when with Mockito.mock with class type:
    // So better to create mock like this:
    // mockRecordHelper = mock(recordHelperClass);
    // Then use Mockito's when(mockRecordHelper.getAccessor(DummyClass.class, testField)).thenReturn(expectedMethod);
    // But compiler error occurs because mockRecordHelper is Object.
    // So cast mockRecordHelper to Object and use reflection to set up stub:
    // Use Mockito's doReturn:
    org.mockito.stubbing.OngoingStubbing<?> stubbing = doReturn(expectedMethod).when(mockRecordHelper);
    getAccessorMethod.invoke(mockRecordHelper, DummyClass.class, testField);

    // Instead of above complicated, use Mockito's "mock" with Answers:
    // Actually, simplest way is to use Mockito's when with reflection:
    // So:
    when(recordHelperClass.getMethod("getAccessor", Class.class, Field.class).invoke(mockRecordHelper, DummyClass.class, testField)).thenReturn(expectedMethod);

    // But above throws checked exception, so wrap in try-catch or use doAnswer:
    // Instead, do this:
    java.lang.reflect.Proxy.newProxyInstance(
      recordHelperClass.getClassLoader(),
      new Class<?>[]{recordHelperClass},
      (proxy, method, args) -> {
        if ("getAccessor".equals(method.getName()) &&
            args.length == 2 &&
            args[0] == DummyClass.class &&
            args[1] == testField) {
          return expectedMethod;
        }
        return null;
      });

    // Instead of all above, just create a proxy mock:
    mockRecordHelper = java.lang.reflect.Proxy.newProxyInstance(
        recordHelperClass.getClassLoader(),
        new Class<?>[]{recordHelperClass},
        (proxy, method, args) -> {
          if ("getAccessor".equals(method.getName()) &&
              args.length == 2 &&
              args[0] == DummyClass.class &&
              args[1] == testField) {
            return expectedMethod;
          }
          if ("getAccessor".equals(method.getName()) &&
              args.length == 2 &&
              (args[0] == DummyClass.class || args[0] == null) &&
              args[1] == null) {
            return null;
          }
          if ("getAccessor".equals(method.getName()) &&
              args.length == 2 &&
              args[0] == null &&
              args[1] == testField) {
            return null;
          }
          return null;
        });

    // Use reflection to set the private static final RECORD_HELPER field in ReflectionHelper
    java.lang.reflect.Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    // Remove final modifier via reflection
    java.lang.reflect.Field modifiersField = java.lang.reflect.Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~Modifier.FINAL);

    recordHelperField.set(null, mockRecordHelper);
  }

  @Test
  void testGetAccessorDelegatesToRecordHelper() {
    Method method = ReflectionHelper.getAccessor(DummyClass.class, testField);
    assertNotNull(method);
    assertEquals(expectedMethod, method);
  }

  @Test
  void testGetAccessorWithNullField() {
    Method method = ReflectionHelper.getAccessor(DummyClass.class, null);
    assertNull(method);
  }

  @Test
  void testGetAccessorWithNullClass() {
    Method method = ReflectionHelper.getAccessor(null, testField);
    assertNull(method);
  }
}
